"use client"

import * as React from "react"
import {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
} from "@/components/ui/pagination"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import { ChevronLeftIcon, ChevronRightIcon } from "lucide-react"

type PaginationLinkData = {
  active: boolean
  label: string
  url: string | null
}

type InertiaLikeLinkProps = {
  href: string
  children: React.ReactNode
  preserveState?: boolean
  preserveScroll?: boolean
}

type Props = {
  links: PaginationLinkData[]
  size?: "default" | "sm" | "lg" | "icon" | null | undefined
  className?: string
  LinkComponent?: React.ComponentType<InertiaLikeLinkProps>
}

export function InertiaPagination({
  links,
  size = "icon",
  className,
  LinkComponent,
}: Props) {
  const cleanLabel = (label: string) =>
    label.replace(/&laquo;|&raquo;/g, "").trim()

  if (!links || links.length <= 1) return null

  return (
    <Pagination className={className}>
      <PaginationContent>
        {links.map((link, index) => {
          const isPrev = link.label.includes("Previous")
          const isNext = link.label.includes("Next")
          const isEllipsis = link.label === "..."
          const isDisabled = !link.url
          const content = (
            <>
              {isPrev && <ChevronLeftIcon className="h-4 w-4" />}
              {isPrev || isNext ? (
                <span className="sr-only">{cleanLabel(link.label)}</span>
              ) : (
                cleanLabel(link.label)
              )}
              {isNext && <ChevronRightIcon className="h-4 w-4" />}
            </>
          )

          return (
            <PaginationItem key={`${link.label}-${index}`}>
              {isEllipsis ? (
                <PaginationEllipsis />
              ) : (
                <Button
                  asChild
                  variant={link.active ? "outline" : "ghost"}
                  size={size}
                  disabled={isDisabled}
                  aria-current={link.active ? "page" : undefined}
                  className={cn(
                    link.active && "pointer-events-none font-semibold",
                    isDisabled && "pointer-events-none opacity-50"
                  )}
                >
                  {LinkComponent ? (
                    <LinkComponent
                      href={link.url ?? "#"}
                      preserveState
                      preserveScroll
                    >
                      {content}
                    </LinkComponent>
                  ) : (
                    <a
                      href={link.url ?? "#"}
                      aria-disabled={isDisabled || undefined}
                    >
                      {content}
                    </a>
                  )}
                </Button>
              )}
            </PaginationItem>
          )
        })}
      </PaginationContent>
    </Pagination>
  )
}

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import {
  ChevronLeftIcon,
  ChevronRightIcon,
  MoreHorizontalIcon,
} from "lucide-react"

import { cn } from "@/lib/utils"
import { buttonVariants } from "@/components/ui/button"

type PaginationLinkSize = "default" | "sm" | "lg" | "icon" | null | undefined

function Pagination({
  className,
  ...props
}: React.ComponentProps<"nav">) {
  return (
    <nav
      role="navigation"
      aria-label="pagination"
      className={cn("mx-auto flex w-full justify-center", className)}
      {...props}
    />
  )
}

function PaginationContent({
  className,
  ...props
}: React.ComponentProps<"ul">) {
  return (
    <ul
      className={cn("flex flex-row items-center gap-1", className)}
      {...props}
    />
  )
}

function PaginationItem(props: React.ComponentProps<"li">) {
  return <li {...props} />
}

function PaginationLink({
  className,
  isActive,
  size = "icon",
  asChild = false,
  ...props
}: React.ComponentProps<"a"> & {
  isActive?: boolean
  size?: PaginationLinkSize
  asChild?: boolean
}) {
  const Comp = asChild ? Slot : "a"

  return (
    <Comp
      aria-current={isActive ? "page" : undefined}
      className={cn(
        buttonVariants({
          variant: isActive ? "outline" : "ghost",
          size,
        }),
        className
      )}
      {...props}
    />
  )
}

function PaginationPrevious({
  className,
  ...props
}: React.ComponentProps<typeof PaginationLink>) {
  return (
    <PaginationLink
      aria-label="Go to previous page"
      size="default"
      className={cn("gap-1 px-2.5 sm:pl-2.5", className)}
      {...props}
    >
      <ChevronLeftIcon className="h-4 w-4" />
      <span>Previous</span>
    </PaginationLink>
  )
}

function PaginationNext({
  className,
  ...props
}: React.ComponentProps<typeof PaginationLink>) {
  return (
    <PaginationLink
      aria-label="Go to next page"
      size="default"
      className={cn("gap-1 px-2.5 sm:pr-2.5", className)}
      {...props}
    >
      <span>Next</span>
      <ChevronRightIcon className="h-4 w-4" />
    </PaginationLink>
  )
}

function PaginationEllipsis({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      aria-hidden
      className={cn("flex h-9 w-9 items-center justify-center", className)}
      {...props}
    >
      <MoreHorizontalIcon className="h-4 w-4" />
      <span className="sr-only">More pages</span>
    </span>
  )
}

export {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationPrevious,
  PaginationNext,
  PaginationEllipsis,
}
